import{_ as e}from"./chunks/IntervalDemo.vue_vue_type_script_setup_true_lang.DZxqM-K9.js";import{C as n,o,c as l,ag as d,E as r,w as i}from"./chunks/framework.DLbVeA01.js";import"./chunks/Piano.QhCkvqJz.js";const m=JSON.parse('{"title":"音程 Intervals","description":"","frontmatter":{},"headers":[],"relativePath":"intervals/index.md","filePath":"intervals/index.md"}'),s={name:"intervals/index.md"},p=Object.assign(s,{setup(h){return(_,t)=>{const a=n("ClientOnly");return o(),l("div",null,[t[0]||(t[0]=d('<h1 id="音程-intervals" tabindex="-1">音程 Intervals <a class="header-anchor" href="#音程-intervals" aria-label="Permalink to &quot;音程 Intervals&quot;">​</a></h1><p><strong>音程</strong>（Interval）是两个音之间的距离。它是乐理中最基础的概念之一 — 旋律是横向的音程序列，和弦是纵向的音程叠加。</p><h2 id="什么是音程" tabindex="-1">什么是音程？ <a class="header-anchor" href="#什么是音程" aria-label="Permalink to &quot;什么是音程？&quot;">​</a></h2><p>当你在钢琴上弹两个不同的音时，它们之间的&quot;距离&quot;就是音程。这个距离用<strong>半音</strong>（semitone）来度量。</p><ul><li><strong>半音</strong>：钢琴上相邻两个键的距离（包括黑键），例如 C → C# 或 E → F</li><li><strong>全音</strong>：两个半音的距离，例如 C → D 或 F → G</li></ul><h2 id="交互式音程演示" tabindex="-1">交互式音程演示 <a class="header-anchor" href="#交互式音程演示" aria-label="Permalink to &quot;交互式音程演示&quot;">​</a></h2><p>选择根音和音程，在钢琴上看到并听到它们：</p>',7)),r(a,null,{default:i(()=>[r(e)]),_:1}),t[1]||(t[1]=d('<h2 id="_12-个基本音程" tabindex="-1">12 个基本音程 <a class="header-anchor" href="#_12-个基本音程" aria-label="Permalink to &quot;12 个基本音程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>半音数</th><th>音程名称</th><th>英文名</th><th>性质</th><th>示例 (从 C)</th></tr></thead><tbody><tr><td>0</td><td>纯一度</td><td>Unison</td><td>完全协和</td><td>C → C</td></tr><tr><td>1</td><td>小二度</td><td>Minor 2nd</td><td>不协和</td><td>C → C#</td></tr><tr><td>2</td><td>大二度</td><td>Major 2nd</td><td>不协和</td><td>C → D</td></tr><tr><td>3</td><td>小三度</td><td>Minor 3rd</td><td>不完全协和</td><td>C → D#</td></tr><tr><td>4</td><td>大三度</td><td>Major 3rd</td><td>不完全协和</td><td>C → E</td></tr><tr><td>5</td><td>纯四度</td><td>Perfect 4th</td><td>完全协和</td><td>C → F</td></tr><tr><td>6</td><td>增四度/减五度</td><td>Tritone</td><td>不协和</td><td>C → F#</td></tr><tr><td>7</td><td>纯五度</td><td>Perfect 5th</td><td>完全协和</td><td>C → G</td></tr><tr><td>8</td><td>小六度</td><td>Minor 6th</td><td>不完全协和</td><td>C → G#</td></tr><tr><td>9</td><td>大六度</td><td>Major 6th</td><td>不完全协和</td><td>C → A</td></tr><tr><td>10</td><td>小七度</td><td>Minor 7th</td><td>不协和</td><td>C → A#</td></tr><tr><td>11</td><td>大七度</td><td>Major 7th</td><td>不协和</td><td>C → B</td></tr><tr><td>12</td><td>纯八度</td><td>Octave</td><td>完全协和</td><td>C → C</td></tr></tbody></table><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="/chords/">和弦</a> — 和弦由多个音程叠加而成</li><li><a href="/scales/">音阶</a> — 音阶是按特定音程模式排列的音符序列</li></ul>',4))])}}});export{m as __pageData,p as default};
